head.script:
//-------------------------------------------------------------------------
// PGM명 : 거래처별손익 인력구성 (co_404_01_57b)
// 작성자 : 송정희
// 최초작성일자 : 2026-12-14
//-------------------------------------------------------------------------
scwin.fromDate_Yy = ""; // 작업날짜 
scwin.fromDate_Yy = WebSquare.date.getCurrentServerDate("yyyy");
scwin.hid_stdYyyy = "";

scwin.sort_options = {};
scwin.sort_options.sortIndex = "acctDeptCd transCargoClsCd";
scwin.sort_options.sortOrder = "1 1";

scwin.delRowIdx = ""; 

scwin.onpageload = function() {
    //cfDisableKey();
    var ds_transCargoClsCd_data = [
                {"transCargoClsCd":"" ,"transCargoClsNm":"전체"}
                , {"transCargoClsCd":"C","transCargoClsNm":"CNTR"}
                , {"transCargoClsCd":"B","transCargoClsNm":"BULK"}
                , {"transCargoClsCd":"E","transCargoClsNm":"기타"}
    ];

    ds_transCargoClsCd.setJSON(ds_transCargoClsCd_data );

    var ds_gr_transCargoClsCd_data = [
                {"transCargoClsCd":"C","transCargoClsNm":"CNTR"}
                , {"transCargoClsCd":"B","transCargoClsNm":"BULK"}
                , {"transCargoClsCd":"E","transCargoClsNm":"기타"}
    ];

    ds_gr_transCargoClsCd.setJSON(ds_gr_transCargoClsCd_data );

    ed_stdYyyy.setValue(scwin.fromDate_Yy);
    scwin.hid_stdYyyy = ed_stdYyyy.getValue();	
    rd_transCargoClsCd.setSelectedIndex(0);

    $c.gus.cfDisableObjects([btn_AddRow, btn_AllDeleteRow, btn_undoRow, btn_Save]);
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    if(ed_stdYyyy.getValue().trim().length <= 0){
        await $c.win.alert("기준년도는 필수입력항목입니다.");
        return;
    }
    if (!$c.gus.cfValidate([ed_stdYyyy])) {
        return;
    }
    $c.sbm.execute(sbm_master);

    // 정상조회후 조회년월,버전에 대한 Hidden값 및 저장가능여부 True로 변경
    scwin.hid_stdYyyy = ed_stdYyyy.getValue();
}

//-------------------------------------------------------------------------
// 엑셀 Download
//-------------------------------------------------------------------------
scwin.f_runExcel = function (varGrNm) {
    var options = {
        fileName: `거래처별손익 인력구성_${ed_stdYyyy.getValue()}.xlsx`,
        sheetName: `거래처별손익 인력구성_${ed_stdYyyy.getValue()}`,
        startRowIndex: 2,
        startColumnIndex: 0,
        type: "1",
        useStyle: true,
        hiddenVisible: true
    };

    var infoArr = [{
        rowIndex: 0,
        colIndex: 0,
        rowSpan: 1,
        colSpan: 10,
        text: "거래처별손익 인력구성",
        textAlign: "center",
        fontSize: 18,
        drawBorder: false,
        fontName: "돋움체"
    }]
    $c.data.downloadGridViewExcel(gr_ClntControl, options, infoArr);
}

//-------------------------------------------------------------------------
// 엑셀 Upload
//-------------------------------------------------------------------------
scwin.f_Upload = async function () {
    //gr_clntfixCostAmt.ReDraw = "false";
    ds_master.removeAll();
    ds_temp.removeAll();
    // ds_excel.DataId = fileUploadGDS.NameValue(0, "filePath");
    // ds_excel.Reset();
    // resetForm('frm');

    if (udc_EX1.getUpExt() == "1") {

        let options = {
            "fileName": "gridDataUpload.csv",
            "status": "C",
            "header":1,
            "type": "1",
            "startRowIndex":0,
            "footerExist":0,
        };

        await $c.data.uploadGridViewCSV(grdTemp, options);

    } else {
        let options = {
            "fileName": "gridDataUpload.xlsx",
            "status": "C",
            "headerExist":1,
            "useMaxByteLength": ",",
            "type": "1",
            "startRowIndex":0,
            "footerExist":0,
        };

        await $c.data.uploadGridViewExcel(grdTemp, options);
    }
};


scwin.grdTemp_onfilereadend = async function (value) {
    var msg = ed_stdYyyy.getValue().trim()+"년 으로 엑셀파일 업로드 하시겠습니까?";
    let rtnval = await $c.win.confirm(msg);
    if(!rtnval){
        ds_temp.removeAll();
        return;
    }else{
        scwin.gr_ClntControl_move();
    }
};


//-------------------------------------------------------------------------    
// 엑셀 Upload - UDC 사용
//-------------------------------------------------------------------------    
//scwin.f_Upload = function () {
//-------------------------------------------------------------------------    	
// 엑셀 파일 업로드 - UDC  ==> upload 후 체크
//-------------------------------------------------------------------------    
scwin.gr_ClntControl_move = async function (){

    console.log("ds_temp>>" , ds_temp.getAllJSON());

    //ds_master.removeAll();

    for(var i=0; i<ds_temp.getRowCount(); i++) {
        ds_master.insertRow(i);
        // 직급코드가 정상적으로 입력되어 있는지 확인함.
        if ( $c.gus.cfIsNull(ds_temp.getCellData(i,"transCargoClsCd")) ) {
            await $c.gus.cfAlertMsg((i+1) + "번째 행의  구분코드 코드값이 없습니다. 확인하시기 바랍니다.");
            return;
        }

        ds_master.setCellData(i,"chk", "F");
        ds_master.setCellData(i,"stdYyyy", ed_stdYyyy.getValue().trim());
        ds_master.setCellData(i,"acctDeptCd", ds_temp.getCellData(i,"acctDeptCd"));
        ds_master.setCellData(i,"acctDeptNm", ds_temp.getCellData(i,"acctDeptNm"));

        ds_master.setCellData(i,"transCargoClsCd", ds_temp.getCellData(i,"transCargoClsCd"));


        ds_master.setCellData(i,"jan", ds_temp.getCellData(i,"jan").trim());
        ds_master.setCellData(i,"feb", ds_temp.getCellData(i,"feb").trim());
        ds_master.setCellData(i,"mar", ds_temp.getCellData(i,"mar").trim());
        ds_master.setCellData(i,"apr", ds_temp.getCellData(i,"apr").trim());
        ds_master.setCellData(i,"may", ds_temp.getCellData(i,"may").trim());
        ds_master.setCellData(i,"jun", ds_temp.getCellData(i,"jun").trim());
        ds_master.setCellData(i,"jul", ds_temp.getCellData(i,"jul").trim());
        ds_master.setCellData(i,"aug", ds_temp.getCellData(i,"aug").trim());
        ds_master.setCellData(i,"sep", ds_temp.getCellData(i,"sep").trim());
        ds_master.setCellData(i,"oct", ds_temp.getCellData(i,"oct").trim());
        ds_master.setCellData(i,"nov", ds_temp.getCellData(i,"nov").trim());
        ds_master.setCellData(i,"dec", ds_temp.getCellData(i,"dec").trim());

        // 인원수에 대한 자릿수를 체크한다. 
        if ( ds_temp.getCellData(i,"jan") > 99999 ) {
            await $c.gus.cfAlertMsg("1월의 입력가능 범위를 초과 하였습니다. 확인하시기 바랍니다.");
            return;
        }			
        if ( ds_temp.getCellData(i,"feb") > 99999) {
            await $c.gus.cfAlertMsg("2월의 입력가능 범위를 초과 하였습니다. 확인하시기 바랍니다.");
            return;
        }
        if ( ds_temp.getCellData(i,"mar") > 99999) {
            await $c.gus.cfAlertMsg("3월의 입력가능 범위를 초과 하였습니다. 확인하시기 바랍니다.");
            return;
        }
        if ( ds_temp.getCellData(i,"apr") > 99999) {
            await $c.gus.cfAlertMsg("4월의 입력가능 범위를 초과 하였습니다. 확인하시기 바랍니다.");
            return;
        }
        if ( ds_temp.getCellData(i,"may") > 99999) {
            await $c.gus.cfAlertMsg("5월의 입력가능 범위를 초과 하였습니다. 확인하시기 바랍니다.");
            return;
        }
        if ( ds_temp.getCellData(i,"jun") > 99999) {
            await $c.gus.cfAlertMsg("6월의 입력가능 범위를 초과 하였습니다. 확인하시기 바랍니다.");
            return;
        }
        if ( ds_temp.getCellData(i,"jul") > 99999) {
            await $c.gus.cfAlertMsg("7월의 입력가능 범위를 초과 하였습니다. 확인하시기 바랍니다.");
            return;
        }
        if ( ds_temp.getCellData(i,"aug") > 99999) {
            await $c.gus.cfAlertMsg("8월의 입력가능 범위를 초과 하였습니다. 확인하시기 바랍니다.");
            return;
        }
        if ( ds_temp.getCellData(i,"sep") > 99999) {
            await $c.gus.cfAlertMsg("9월의 입력가능 범위를 초과 하였습니다. 확인하시기 바랍니다.");
            return;
        }
        if ( ds_temp.getCellData(i,"oct") > 99999) {
            await $c.gus.cfAlertMsg("10월의 입력가능 범위를 초과 하였습니다. 확인하시기 바랍니다.");
            return;
        }
        if ( ds_temp.getCellData(i,"nov") > 99999) {
            await $c.gus.cfAlertMsg("11월의 입력가능 범위를 초과 하였습니다. 확인하시기 바랍니다.");
            return;
        }
        if ( ds_temp.getCellData(i,"dec") > 99999) {
            await $c.gus.cfAlertMsg("12월의 입력가능 범위를 초과 하였습니다. 확인하시기 바랍니다.");
            return;
        }
    }

    console.log("ds_master 22 >>" , ds_master.getAllJSON());

    // 엑셀파일 Import가 정상종료시 조회년월,버전에 대한 Hidden값 및 저장가능여부 True로 변경
    scwin.hid_stdYyyy = ed_stdYyyy.getValue();

    ds_temp.removeAll();

    var rowCnt = ds_master.getTotalRow();
    totalRows.setValue(rowCnt);	
    $c.gus.cfEnableObjects([btn_AddRow, btn_AllDeleteRow, btn_undoRow, btn_Save]);
    ds_master.setRowPosition(rowCnt);        
};


//-------------------------------------------------------------------------
// 엑셀 출력
//-------------------------------------------------------------------------
scwin.f_Excel = async function() {
   if(ds_master.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    }

    let gridColCount = 0;
    for(let i = 0; i < gr_ClntControl.getTotalCol(); i++){
        if(gr_ClntControl.getColumnVisible(i)==true){
            gridColCount++;
        }
    }

    let str = $c.gus.cfGetFormatStr(ed_stdYyyy.getValue(), "####");

    let startRowIndex = 0;
    let infoArr = [{
        rowIndex : 0,             
        colIndex : 0,            
        colSpan : gridColCount,   
        rowSpan : 1,
        text : "거래처별손익 인력구성",
        textAlign : "center",    
        fontSize : 12,
        drawBorder : false,       
        color : "black",          
        backgroundColor : "#ffffff" 
    },{
        rowIndex : 1,             
        colIndex : 0,           
        colSpan : gridColCount,  
        rowSpan : 1,
        text : "년도 ["+ str +"]",
        textAlign : "left",    
        fontSize : 10,
        drawBorder : false,       
        color : "black",       
        backgroundColor : "#ffffff" 
    }]

    const options = {
        fileName: "거래처별손익 인력구성.xlsx",
        sheetName: "년도" + str ,
        startRowIndex : 2,        
        startColumnIndex : 0,
        type : 1
    };
    await $c.data.downloadGridViewExcel(gr_ClntControl, options, infoArr);
};

//-------------------------------------------------------------------------
//  행전체삭제
//-------------------------------------------------------------------------
scwin.f_AllDeleteRow = function () {
    // ds_master.removeAll();
    var rcnt = ds_master.getRowCount();
    for(var i=0; i < rcnt; i++) {
        ds_master.deleteRow(i);
    }

    gr_ClntControl.setFocusedCell(0,0);

};

//-------------------------------------------------------------------------
// 행추가 버튼 클릭시 
//-------------------------------------------------------------------------
scwin.f_AddRow = function () {

    // 필수 입력사항 체크
    if (!$c.gus.cfValidate([ed_stdYyyy])) {
        return;
    }

    let row = ds_master.getRowCount();
    ds_master.insertRow(row);

    ds_master.setCellData(row, "stdYyyy", ed_stdYyyy.getValue().trim());    
    ds_master.setRowPosition(row);
    gr_ClntControl.setFocusedCell(row, 0, true);
};

//-------------------------------------------------------------------------
// 행삭제버튼 클릭시 
//-------------------------------------------------------------------------
scwin.f_DeleteRow = function () {
    scwin.delRowIdx = ds_master.getRowPosition();
    let positionRow = 0;
    if(ds_master.getRowStatus(scwin.delRowIdx) == "C"){        
	    ds_master.removeRow(scwin.delRowIdx);
        positionRow = ds_master.getRowCount();
    }else{        
	    ds_master.deleteRow(scwin.delRowIdx);
        positionRow = scwin.delRowIdx;
    }
    gr_ClntControl.setFocusedCell(positionRow,0);
};

//-------------------------------------------------------------------------    
// 취소 버튼 클릭시 
//-------------------------------------------------------------------------
scwin.f_UndoRow = function () {  

    var row = ds_master.getRowPosition();

    if (gr_ClntControl.getFocusedRowStatus() == "C") { //추가된 행
        ds_master.undoRow(row);
        ds_master.removeRow(row);

    } else if (gr_ClntControl.getFocusedRowStatus() == "D") { // 삭제된 행
        ds_master.undoRow(row);
    }
};

scwin.btn_allDeleteRow_onclick = function (e) {
    scwin.f_AllDeleteRow();
};

scwin.btn_Cancel_onclick = function (e) {
    scwin.f_UndoRow();
};

scwin.btn_Save_onclick = function (e) {
    scwin.f_Save();
};


//-------------------------------------------------------------------------
// 저장시 호출 되는 함수
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    if ( ed_stdYyyy.getValue().trim() != scwin.hid_stdYyyy ) {
        await $c.gus.cfAlertMsg("조회 조건인 기준년도가 변경되어서 저장 하실 수 없습니다. 재 조회 및 엑셀파일 Import를 다시 실행하시기 바랍니다.");
        return;
    }

    if (ds_master.getModifiedIndex().length <= 0 ) {
        await $c.win.alert("변경된 사항이 없습니다.");
        //await $c.win.alert($c.data.getMessage(MSG_CM_ERR_001, [""]));
        return;
    } 
    // 변경된 사항이 있는지 확인.
    var tmm = "";
    var rcnt = ds_master.getRowCount();
    const cols = ["jan", "feb", "mar", "apr", "may", "jun", "jul", "aug", "sep", "oct", "nov", "dec"];

    for(var i=0; i <= rcnt; i++) {
        if(ds_master.getRowStatus(i)=="C" || ds_master.getRowStatus(i)=="U" ) {       
            ds_master.setCellData(i, "chk", "F");
            ds_master.setCellData(i, "stdYyyy", scwin.hid_stdYyyy);

            tmm = String(i+1);            
            ds_master.setCellData(i, "stdYm", scwin.hid_stdYyyy + $c.gus.cfGetFormatStr(tmm,"0#"));

			if ($c.gus.cfIsNull(ds_master.getCellData(i,"acctDeptCd")) ) {
				await $c.gus.cfAlertMsg((i+1) + "번째 행의  귀속코드 코드값이 없습니다. 확인하시기 바랍니다.");
                gr_ClntControl.setFocusedCell(i, "acctDeptCd", true);
				return true;
			}
			if ($c.gus.cfIsNull(ds_master.getCellData(i,"transCargoClsCd")) ) {
				await $c.gus.cfAlertMsg((i+1) + "번째 행의  구분코드 코드값이 없습니다. 확인하시기 바랍니다.");
                gr_ClntControl.setFocusedCell(i, "transCargoClsCd", true);
				return true;
			}
			// 인원수에 대한 자릿수를 체크한다.
            t_StaffCnt = 0; 
            for (var j=0; j < cols.length; j++) {
                if ( $c.gus.cfIsNull(ds_master.getCellData(i, cols[j])) || ds_master.getCellData(i, cols[j]) > 99999 ) {
                    await $c.gus.cfAlertMsg(String(j+1)+ "월의 입력가능 범위를 초과 하였습니다. 확인하시기 바랍니다.");
                    gr_ClntControl.setFocusedCell(i, cols[j], true);
                    return true;
                }    
                t_StaffCnt = t_StaffCnt + $c.num.parseInt(ds_master.getCellData(i, cols[j]));
            }
            ds_master.setCellData(i, "staffCnt", t_StaffCnt);   
        }
    }  

    // 필수입력사항 확인
//    if (!$c.gus.cfValidate([gr_ClntControl])) {
//        return;
//    }    

    if (await $c.win.confirm(MSG_CM_CRM_001) == false) {
        return;
    }    

    var rs = $c.sbm.execute(sbm_Save);

    //if (rs.responseJSON.resultDataSet[0].code == "1"){
    //    await $c.win.alert(MSG_CM_INF_001);	// 성공적으로 저장하였습니다.
    //    ds_master.reform();
    //    scwin.f_Retrieve();
    //}    
}

//-------------------------------------------------------------------------
// 사업영역코드팝업 
//-------------------------------------------------------------------------
scwin.f_bizDomCdPopUp = function(e) {
    udc_bizDomCd.cfCommonPopUp(scwin.udc_bizDomCd_callBackFunc
                        , ed_bizDomCd.getValue(),ed_bizDomNm.getValue()
                        , "T"                             // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , null                            // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , "T"                             // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        );      
};

scwin.udc_bizDomCd_callBackFunc = function (ret) {
    if (ret[0] != "N/A" && !$c.gus.cfIsNull(ret)) {    
        ed_bizDomCd.setValue(ret[0]);
        ed_bizDomNm.setValue(ret[1]);
	} else {
        ed_bizDomCd.setValue("");
        ed_bizDomNm.setValue("");
	}         
};

//-------------------------------------------------------------------------
// 부서코드팝업 acctDeptCd
//-------------------------------------------------------------------------
scwin.f_acctDeptCdPopUp = function(e) { 
    udc_acctDeptCd.cfCommonPopUp(scwin.udc_acctDeptCd_callBackFunc
                        , ed_acctDeptCd.getValue(),ed_acctDeptNm.getValue()
                        , "T"                             // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , null                            // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , "F"                             // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        );                                    
};

scwin.udc_acctDeptCd_callBackFunc = function (ret) {
console.log("udc_acctDeptCd_callBackFunc");        
    console.log(ret); 
    if (ret[0] != "N/A" && !$c.gus.cfIsNull(ret)) {    
        ed_acctDeptCd.setValue(ret[0]);
        ed_acctDeptNm.setValue(ret[1]);
	} else {
        ed_acctDeptCd.setValue("");
        ed_acctDeptNm.setValue("");
	}         
};

//-------------------------------------------------------------------------
// 팝업 여부 검사
//-------------------------------------------------------------------------
scwin.f_IsPopUp = function (inObj, inObjNm) {

    let inValue1 = $c.gus.cfGetValue(inObj);
    let inValue2 = $c.gus.cfGetValue(inObjNm);    

    if ($c.gus.cfIsNull(inValue1) && $c.gus.cfIsNull(inValue2)) {
        for (var i = 1; i < scwin.f_IsPopUp.arguments.length; i++) {
            $c.gus.cfSetValue(scwin.f_IsPopUp.arguments[i], "");
        }
        return false;
    }
    return true;
}

