scwin.btn_Search_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.gr_ClntControl_oncellclick = function (rowIndex, columnIndex, columnId) {
    if (columnId == "acctDeptNm" ) return;
	if ( ( columnId == "acctDeptCd" || columnId == "transCargoClsCd" ) && ds_master.getRowStatus(rowIndex) == "C") {
        gr_ClntControl.setColumnReadOnly("acctDeptCd", false);
        gr_ClntControl.setColumnReadOnly("transCargoClsCd", false);
	 } else {
        gr_ClntControl.setColumnReadOnly("acctDeptCd", true);
        gr_ClntControl.setColumnReadOnly("transCargoClsCd", true);
	}
};


scwin.gr_ClntControl_ontextimageclick = async function (rowIndex, columnIndex) {
    let colId = gr_ClntControl.getColumnID(columnIndex);
    let value = ds_master.getCellData(rowIndex,colId);
    if (colId == "acctDeptCd") {        
        await udc_acctDeptCd.cfCommonPopUp(scwin.udc_acctDeptCdInfo_callBackFunc
                            , value, ""
                            , "F"                             // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                            , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                            , null                            // Title순서
                            , null                            // 보여주는 각 컬럼들의 폭
                            , null                            // 컬럼중에서 숨기는 컬럼 지정
                            , null                            // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                            , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                            , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                            , null                            // 윈도우 위치 Y좌표
                            , null                            // 윈도우 위치 X좌표
                            , null                            // 중복체크여부	("F")
                            , "F"                             // 전체검색허용여부	("F")
                            , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                            );    
    }                                   
};    

scwin.udc_acctDeptCdInfo_callBackFunc = async function(ret) {
    let row = gr_ClntControl.getFocusedRowIndex();
    if (ret[0] != "N/A" && !$c.gus.cfIsNull(ret)) {    
        ds_master.setCellData(row, "acctDeptCd", ret[0]);
        ds_master.setCellData(row, "acctDeptNm", ret[1]);
	} else {
        ds_master.setCellData(row, "acctDeptCd", "");
        ds_master.setCellData(row, "acctDeptNm", "");
    }        
};

scwin.gr_ClntControl_onviewchange = function (info) {
    var colId = gr_ClntControl.getColumnID(info.colIndex);

    if(colId == "transCargoClsCd") { 
        let opts = scwin.f_custom_Info(info.newValue);
        gr_ClntControl.setCellInputType(info.rowIndex, "transCargoClsCd", opts);                               
    }

    let newData = info.newValue;
    let oldData = info.oldValue;

    if (colId == "acctDeptCd") {
        if ($c.gus.cfIsNull(newData)) {
            ds_master.setCellData(info.rowIndex, "acctDeptNm", "");
            return;
        }
        if (newData == oldData) return;

    } else if (colId == "transCargoClsCd") {
        if ($c.gus.cfIsNull(newData)) {
            ds_master.setCellData(info.rowIndex, "transCargoClsCd", "");
            return;
        }       
    }

};

// type 에 맞는 info 정보 셋팅
scwin.f_custom_Info = function(type) {
    let ret = "";

    switch(type) {
        case "select" :
            ret = {
                inputType : "select",
                options : {
                    viewType: "icon", chooseOption: true
                },
                itemSet : {
                    nodeset: "data:ds_gr_transCargoClsCd", 
                    label: "transCargoClsNm",
                    value: "transCargoClsCd"
                }
            };
            break;
    }        
    return ret;
};


scwin.sbm_Save_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC"){
        $c.win.alert(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
        ds_master.reform();
        scwin.f_Retrieve();
    }    
};

